56	
57		private final SpringApplication application;
58	
59		private final String[] args;
60	
61		private final SimpleApplicationEventMulticaster initialMulticaster;
62	
63		EventPublishingRunListener(SpringApplication application, String[] args) {
64			this.application = application;
65			this.args = args;
66			this.initialMulticaster = new SimpleApplicationEventMulticaster();
67		}
68	
69		@Override
70		public int getOrder() {
71			return 0;
72		}
73	
74		@Override
75		public void starting(ConfigurableBootstrapContext bootstrapContext) {
76			multicastInitialEvent(new ApplicationStartingEvent(bootstrapContext, this.application, this.args));
77		}
78	
79		@Override
