81				ConfigurableEnvironment environment) {
82			multicastInitialEvent(
83					new ApplicationEnvironmentPreparedEvent(bootstrapContext, this.application, this.args, environment));
84		}
85	
86		@Override
87		public void contextPrepared(ConfigurableApplicationContext context) {
88			multicastInitialEvent(new ApplicationContextInitializedEvent(this.application, this.args, context));
89		}
90	
91		@Override
92		public void contextLoaded(ConfigurableApplicationContext context) {
93			for (ApplicationListener<?> listener : this.application.getListeners()) {
94				if (listener instanceof ApplicationContextAware contextAware) {
95					contextAware.setApplicationContext(context);
96				}
97				context.addApplicationListener(listener);
98			}
99			multicastInitialEvent(new ApplicationPreparedEvent(this.application, this.args, context));
100		}
101	
102		@Override
103		public void started(ConfigurableApplicationContext context, @Nullable Duration timeTaken) {
104			context.publishEvent(new ApplicationStartedEvent(this.application, this.args, context, timeTaken));
105			AvailabilityChangeEvent.publish(context, LivenessState.CORRECT);
106		}
107	
108		@Override
109		public void ready(ConfigurableApplicationContext context, @Nullable Duration timeTaken) {
110			context.publishEvent(new ApplicationReadyEvent(this.application, this.args, context, timeTaken));
111			AvailabilityChangeEvent.publish(context, ReadinessState.ACCEPTING_TRAFFIC);
112		}
113	
114		@Override
115		public void failed(@Nullable ConfigurableApplicationContext context, Throwable exception) {
116			ApplicationFailedEvent event = new ApplicationFailedEvent(this.application, this.args, context, exception);
117			if (context != null && context.isActive()) {
118				// Listeners have been registered to the application context so we should
119				// use it at this point if we can
120				context.publishEvent(event);
121			}
122			else {
123				// An inactive context may not have a multicaster so we use our multicaster to
124				// call all the context's listeners instead
125				if (context instanceof AbstractApplicationContext abstractApplicationContext) {
126					for (ApplicationListener<?> listener : abstractApplicationContext.getApplicationListeners()) {
127						this.initialMulticaster.addApplicationListener(listener);
128					}
129				}
130				this.initialMulticaster.setErrorHandler(new LoggingErrorHandler());
131				this.initialMulticaster.multicastEvent(event);
132			}
133		}
134	
135		private void multicastInitialEvent(ApplicationEvent event) {
136			refreshApplicationListeners();
137			this.initialMulticaster.multicastEvent(event);
138		}
139	
140		private void refreshApplicationListeners() {
141			this.application.getListeners().forEach(this.initialMulticaster::addApplicationListener);
142		}
143	
144		private static final class LoggingErrorHandler implements ErrorHandler {
145	
146			private static final Log logger = LogFactory.getLog(EventPublishingRunListener.class);
147	
148			@Override
149			public void handleError(Throwable throwable) {
150				logger.warn("Error calling ApplicationEventListener", throwable);
151			}
152	
153		}
154	
155	}
