232						type.addModifiers(Modifier.PUBLIC);
233						type.addJavadoc("Configure the environment with AOT optimizations.");
234						type.addSuperinterface(EnvironmentPostProcessor.class);
235					});
236				generatedClass.getMethods().add("postProcessEnvironment", (method) -> {
237					method.addModifiers(Modifier.PUBLIC);
238					method.addAnnotation(Override.class);
239					method.addParameter(ConfigurableEnvironment.class, ENVIRONMENT_VARIABLE);
240					method.addParameter(SpringApplication.class, "application");
241					method.addCode(generateActiveProfilesInitializeCode());
242				});
243				generationContext.getRuntimeHints()
244					.reflection()
245					.registerType(GeneratedTypeReference.of(generatedClass.getName()),
246							MemberCategory.INVOKE_PUBLIC_CONSTRUCTORS);
247			}
248	
249			private CodeBlock generateActiveProfilesInitializeCode() {
250				CodeBlock.Builder code = CodeBlock.builder();
251				for (String activeProfile : this.activeProfiles) {
252					code.addStatement("$L.addActiveProfile($S)", ENVIRONMENT_VARIABLE, activeProfile);
253				}
254				return code.build();
255			}
