572		/**
573		 * Strategy method used to create the {@link ApplicationContext}. By default this
574		 * method will respect any explicitly set application context class or factory before
575		 * falling back to a suitable default.
576		 * @return the application context (not yet refreshed)
577		 * @see #setApplicationContextFactory(ApplicationContextFactory)
578		 */
579		protected ConfigurableApplicationContext createApplicationContext() {
580			ConfigurableApplicationContext context = this.applicationContextFactory
581				.create(this.properties.getWebApplicationType());
582			Assert.state(context != null, "ApplicationContextFactory created null context");
583			return context;
584		}
585	
586		/**
587		 * Apply any relevant post-processing to the {@link ApplicationContext}. Subclasses
588		 * can apply additional processing as required.
589		 * @param context the application context
590		 */
591		protected void postProcessApplicationContext(ConfigurableApplicationContext context) {
592			if (this.beanNameGenerator != null) {
593				context.getBeanFactory()
594					.registerSingleton(AnnotationConfigUtils.CONFIGURATION_BEAN_NAME_GENERATOR, this.beanNameGenerator);
595			}
596			if (this.resourceLoader != null) {
597				if (context instanceof GenericApplicationContext genericApplicationContext) {
598					genericApplicationContext.setResourceLoader(this.resourceLoader);
599				}
600				if (context instanceof DefaultResourceLoader defaultResourceLoader) {
601					defaultResourceLoader.setClassLoader(this.resourceLoader.getClassLoader());
602				}
603			}
604			if (this.addConversionService) {
605				context.getBeanFactory().setConversionService(context.getEnvironment().getConversionService());
606			}
607		}
